INSERT INTO properties (reference, title, title_nl, title_en, description, description_nl, description_en, price, slug_fr, slug_nl, slug_en, surface, rooms, bedrooms, bathrooms, property_type, condition, status, location_city, location_region, location_address, features, energy_rating, published)
VALUES
('SEC-1266', 'Rojales: Sublimes appartements trois chambres', 'Rojales: Sublieme appartementen met drie slaapkamers', '', 'Ces appartements aux finitions luxueuses se situent à Rojales, ils sont proches de tous les types de commerces et du golf de la Marquesa. La mer et la station balnéaire de Guardamar sont à 8 km. La résidence jouit donc d''un environnement calme tout en étant très proche de l''animation. La résidence est équipée d''une belle grande piscine extérieure, de jolis jardins arborés, d''une salle de fitness, d''une piscine couverte, d''un hammam, un sauna, de hamacs et d''une zone barbecue Le complexe propose des appartements vastes et très lumineux avec trois chambres, deux ou trois salles de bains, une cuisine ouverte, un salon / salle à manger donnant sur une grande terrasse d''où vous pourrez profiter des vues sur la mer. Les appartements du rez-de-chaussée disposent d''un jardin, ceux du premier profitent d''un solarium et d''un ascenseur privé. Un emplacement de parking en plein air est attribué à chaque unité. Sont compris dans le prix les électroménagers, l''air conditionné, les luminaires intérieurs et extérieurs, les volets électriques, l?ascenseur pour les appartements du premier étage et les jardins pour ceux du rez-de-chaussée. Prix pour un rez-de-chaussée avec jardin: de 329.000 ? à 349.000 ? hors frais Prix pour un premier étage avec solarium: 369.000 ? hors frais', 'Deze appartementen met luxueuze afwerking bevinden zich in Rojales, dicht bij alle handelszaken en de golfbaan van La Marquesa. De zee en badplaats Guardamar liggen op 8 km afstand. De residentie ligt in een rustige omgeving en bevindt zich zeer dicht bij de animatie. De residentie is uitgerust met een prachtig groot buitenzwembad, mooie tuinen, een fitnessruimte, een binnenzwembad, een hamam, een sauna, hangmatten en een barbecue. Ruime en zeer goed verlichte appartementen met drie slaapkamers, twee of drie badkamers, een open keuken, een woon- en eetkamer die uitkomt op een groot terras van waaruit u kunt genieten van het uitzicht op de zee. een tuin. De appartementen op de eerste verdieping genieten van een dakterras en een privélift. Aan elke unit is een parkeerplaats toegewezen. Inbegrepen in de prijs zijn keukentoestellen, airconditioning, binnen- en buitenverlichting, elektrische rolluiken, lift voor de eerste verdieping en tuinen voor de woningen op het gelijkvloers. Prijs voor een gelijkvloers met tuin vanaf ? 329.000 exclusief kosten Prijs voor een eerste verdieping met dakterras: ? 369.000 exclusief kosten', '', 329000, 'rojales-sublimes-appartements-trois-chambres', 'rojales-sublieme-appartementen-met-drie-slaapkamers', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1275', 'Benahavis: Villas écologiques quatre chambres', 'Benahavis: ecologische villa''s met vier slaapkamers', '', 'Bien plus qu''un projet, voici une véritable philosophie de vie! Ces 13 villas se construisent dans le respect de l''environnement et a obtenu la certification BREEM. Plus de 5000 m² plantés et arborés de plantes et arbres locaux sont à disposition des propriétaires; vous y trouverez un potager commun, des arbres fruitiers, une piscine, des pergolas, des terrasses,... le tout est votre disposition. La résidence est située sur les hauteurs, elle offre de ce fait des vues panoramiques sur la mer. Quelques-uns des plus beaux golfs de la région sont des les proches alentours. Les villas ont été conçues par des architectes renommés et ils ont choisi des matériaux les plus respectueux de la nature. Les villas se composent de 4 chambres, trois salles de bains, d''un WC invité, une buanderie, une superbe cuisine ouverte, un salon et une salle à manger. Prix à partir 1.990.000 euros hors frais', 'Veel meer dan zomaar een project, dit is een ware levensfilosofie! Deze 13 villa''s zijn gebouwd met respect voor het milieu en hebben de BREEM-certificering behaald. Meer dan 5000m² beplanting, met lokale planten en bomen, zijn ter beschikking van de bewoners. U vindt een gemeenschappelijke moestuin, fruitbomen, een zwembad, pergola''s, terrassen ... alles staat ter uwer beschikking. De accommodatie ligt in de hoogte en biedt een panoramisch uitzicht op de zee. Een aantal van de mooiste golfbanen zijn in de buurt gelegen. De villa''s zijn ontworpen door gerenommeerde architecten en zij hebben dan ook voor de meest natuurvriendelijke materialen gekozen. De villa''s bestaan uit vier slaapkamers, drie badkamers, een apart gastentoilet, een wasruimte, een prachtige open keuken, een woon- en eetkamer. Prijs vanaf ?1.990.000 exclusief kosten.', '', 1990000, 'benahavis-villas-ecologiques-quatre-chambres', 'benahavis-ecologische-villa-s-met-vier-slaapkamers', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1335', 'Villamartin: très beaux appartements en deux chambres', 'LAST UNIT! Villamartin : Prachtige appartementen met twee slaapkamers', '', 'Cette résidence est localisée dans un quartier calme et sécure de Villamartin. Elle est proche de tous les types de commerces et de services. Dans les environs immédiats, se trouvent quatre superbes golfs, le centre commercial La Zenia Boulevard, des supermarchés, de belles plages ouvertes toutes l''année, des restaurants et des bars. Les appartements sont richement dotés, confortables et jouissent de belles finitions. Chaque appartement dispose d''une place de parking en sous-sol ainsi que d''une cave. Une piscine commune, une piscine pour enfants, une aire de jeux, des espaces verts et un jacuzzi sont accessibles pour les propriétaires. Les électroménagers et la climatisation sont inclus dans le prix. Prix à partir de 255.000 ? hors frais Livraison: septembre 2025', 'Deze residentie ligt in een rustige en veilige buurt van Villamartin. Het ligt dicht bij alle soorten bedrijven en diensten. In de directe omgeving zijn er vier prachtige golfbanen, het winkelcentrum La Zenia Boulevard, supermarkten, prachtige stranden die het hele jaar door geopend zijn, restaurants en bars. De appartementen zijn rijkelijk uitgerust, comfortabel en hebben mooie afwerkingen. Elk appartement beschikt over een parkeerplaats en een kelder. Een gemeenschappelijk zwembad, een kinderbad, een speeltuin, groene zones en een jacuzzi zijn beschikbaar voor eigenaars. Elektro en airco toestellen zijn in de prijs inbegrepen. Prijs vanaf 255.000 euro exclusief kosten. Oplevering: september 2025', '', 255000, 'villamartin-tres-beaux-appartements-en-deux-chambres', 'last-unit-villamartin-prachtige-appartementen-met-twee-slaapkamers', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1362', 'Aguilas: superbes appartements trois chambres', 'Aguilas : prachtige appartementen met 3 kamers', '', 'Ce nouveau projet se situe sur les renforts de la montagne, offrant ainsi des vues extraordinaires sur la mer. Il se situe à 5 minutes du centre d''Aguilas, de ses commerces, bars et restaurants. La résidence propose deux belles grandes piscines, une aire de jeux pour les enfants, une zone chill out et enfin un jardin commun. Tous les appartements jouissent d''une place de parking en sous-sol avec la pré-installation pour une borne de recharge électrique. Les appartements se composent de trois chambres, de deux salles de bains et d''une grande pièce de vie regroupant cuisine ouverte, salon et salle à manger. Vous profiterez aussi de belles grandes terrasses. Les cuisines sont livrées avec four, four micro-ondes, plaque de cuisson et hotte. La climatisation est aussi comprise dans le prix. Prix: A partir de 341.000 ? hors frais', 'Dit nieuwe project ligt op de versterkingen van de berg en biedt een buitengewoon uitzicht op de zee, op 5 minuten van het centrum van Aguilas, zijn winkels, bars en restaurants. De residentie biedt twee mooie grote zwembaden, een speeltuin voor kinderen, een ontspanningsruimte en ten slotte een gemeenschappelijke tuin. Alle appartementen hebben een parkeerplaats ondergronds met pre-installatie voor een elektrisch laadstation. De appartementen bestaan uit twee of drie slaapkamers, twee badkamers en een grote woonkamer met open keuken, woonkamer en eetkamer. U zult ook genieten van prachtige grote terrassen. De keukens worden geleverd met oven, magnetron, kookplaat en afzuigkap. Airconditioning is ook bij de prijs inbegrepen. Prijs: vanaf 341.000 euro exclusief kosten', '', 341000, 'aguilas-superbes-appartements-trois-chambres', 'aguilas-prachtige-appartementen-met-3-kamers', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1418', 'San Roque: sublimes appartements au coeur d''un golf en deux chambres', 'San Roque : schitterende appartementen met twee kamers gelegen op een golf', '', 'San Roque est un charmant village andalou, une oasis de tranquillité proche de Sotogrande et de son port de plaisance. Toutes les facilités en termes de produits et de services sont toutes proches. Le complexe, outre deux parcours de golf, dispose d''un court de tennis, d''une très belle piscine et de jardins communs. Ces 24 appartements et duplex offrent de larges terrasses (de 28 m² à 41 m²) et de splendides vues. Les finitions sont de premier ordre et les matériaux choisis sont de grande qualité. Les appartements ont obtenu une classe énergétique B. Un garage et une cave sont inclus dans le prix ainsi que les électroménagers Balay (ou équivalent) et l''air conditionné. Prix à partir de 405.000 ? hors frais Fin des travaux : octobre 2025', 'San Roque is een charmant Andalusisch dorp, een oase van rust in de buurt van Sotogrande en de jachthaven. Alle voorzieningen op het gebied van producten en diensten zijn allemaal dichtbij. Het complex heeft, naast twee golfbanen, een tennisbaan, een prachtig zwembad en gemeenschappelijke tuinen. Deze 24 appartementen en duplexen bieden grote terrassen (van 28 m² tot 41 m²) en een prachtig uitzicht. De afwerkingen zijn eersteklas en de gekozen materialen zijn van hoge kwaliteit. De appartementen hebben energieklasse B. Een garage en een kelder zijn inbegrepen in de prijs, evenals Balay-apparaten (of gelijkwaardig) en airconditioning. Prijs vanaf 405.000 ? exclusief kosten', '', 405000, 'san-roque-sublimes-appartements-au-coeur-d-un-golf-en-deux-chambres', 'san-roque-schitterende-appartementen-met-twee-kamers-gelegen-op-een-golf', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1419', 'San Roque: magnifiques appartements au c?ur d''un golf en trois chambres', 'San Roque : schitterende appartementen met drie kamers gelegen op een golf', '', 'San Roque est un charmant village andalou, une oasis de tranquillité proche de Sotogrande et de son port de plaisance. Toutes les facilités en termes de produits et de services sont toutes proches. Le complexe, outre deux parcours de golf, dispose d''un court de tennis, d''une très belle piscine et de jardins communs. Ces 24 appartements et duplex offrent de larges terrasses ( de 27 m² à 128 m²) et de splendides vues. Les finitions sont de premier ordre et les matériaux choisis sont de grande qualité. Les appartements ont obtenu une classe énergétique B. Un garage et une cave sont inclus dans le prix ainsi que les électroménagers Balay (ou équivalent) et l''air conditionné. Prix à partir de 460.000 ? hors frais Fin des travaux: octobre 2025', 'San Roque is een charmant Andalusisch dorp, een oase van rust in de buurt van Sotogrande en de jachthaven. Alle voorzieningen op het gebied van producten en diensten zijn in de buurt. Het complex heeft, naast twee golfbanen, een tennisbaan, een prachtig zwembad en gemeenschappelijke tuinen. Deze 24 appartementen en duplexen bieden grote terrassen (van 27 m² tot 128 m²) en een prachtig uitzicht. De afwerkingen zijn eersteklas en de gekozen materialen zijn van hoge kwaliteit. De appartementen hebben energieklasse B. Een garage en een kelder zijn inbegrepen in de prijs, evenals Balay-apparaten (of gelijkwaardig) en airconditioning. Prijs vanaf 460.000 euro exclusief kosten', '', 460000, 'san-roque-magnifiques-appartements-au-c-ur-d-un-golf-en-trois-chambres', 'san-roque-schitterende-appartementen-met-drie-kamers-gelegen-op-een-golf', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1420', 'San Roque: superbe pentouse en trois chambres au c?ur d''un golf', 'San Roque : schitterende penthouse met drie kamers gelegen op een golf', '', 'San Roque est un charmant village andalou, une oasis de tranquillité proche de Sotogrande et de son port de plaisance. Toutes les facilités en termes de produits et de services sont toutes proches. Le complexe, outre deux parcours de golf, dispose d''un court de tennis, d''une très belle piscine et de jardins communs. Ces duplex offrent de larges terrasses de 88 m² et de splendides vues. Les finitions sont de premier ordre et les matériaux choisis sont de grande qualité. Les appartements ont obtenu une classe énergétique B. Un garage et une cave sont inclus dans le prix ainsi que les électroménagers Balay (ou équivalent) et l''air conditionné. Prix à partir de 640.000 euros hors frais Fin des travaux: octobre 2024 ou octobre 2025', 'San Roque is een charmant Andalusisch dorp, een oase van rust in de buurt van Sotogrande en de jachthaven. Alle voorzieningen op het gebied van producten en diensten zijn in de buurt. Het complex heeft, naast twee golfbanen, een tennisbaan, een prachtig zwembad en gemeenschappelijke tuinen. Deze duplexen bieden grote terrassen van 88 m² en een prachtig uitzicht. De afwerkingen zijn eersteklas en de gekozen materialen zijn van hoge kwaliteit. De appartementen hebben energieklasse B. Een garage en een kelder zijn inbegrepen in de prijs, evenals Balay-apparaten (of gelijkwaardig) en airconditioning. Prijs vanaf 640.000 euro exclusief kosten.', '', 640000, 'san-roque-superbe-pentouse-en-trois-chambres-au-c-ur-d-un-golf', 'san-roque-schitterende-penthouse-met-drie-kamers-gelegen-op-een-golf', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1476', 'Estepona: magnifiques appartements deux chambres', 'Estepona: mooie tweekamerappartementen', '', 'Ce nouveau complexe se trouve entre mer, montagne et golf à courte distance de tous les types de commerces et services, à 45 minutes de l''aéroport de Malaga et à 10 minutes de Marbella. Chaque appartement a été conçu séparément pour optimiser les espaces et la lumière naturelle. Modernité, élégance et fonctionnalité s''unissent dans un style résolument contemporain.Il sont proposés en deux, trois ou quatre chambres Les espaces communs sont richement dotés avec de beaux jardins, deux piscines, une salle de sport et un club house. Les cuisines sont équipées d''une plaque à induction, un four , un micro-ondes et une hotte. Un parking et une cave sont compris dans le prix. Prix: à partir de 350.000 ? hors frais Fin des travaux : décembre 2025', 'Dit nieuwe complex is gelegen tussen de zee, de bergen en de golfbaan op korte afstand van alle soorten winkels en diensten, op 45 minuten van het vliegveld van Malaga en 10 minuten van Marbella. Elk appartement is afzonderlijk ontworpen om de ruimte en het natuurlijke licht te optimaliseren. Moderniteit, elegantie en functionaliteit worden gecombineerd in een resoluut eigentijdse stijl en zijn beschikbaar in twee, drie of vier slaapkamers. De gemeenschappelijke ruimtes zijn rijkelijk voorzien van prachtige tuinen, twee zwembaden, een fitnessruimte en een clubhuis. De keukens zijn uitgerust met een inductiekookplaat, oven, magnetron en afzuigkap. Parkeren en een kelder zijn bij de prijs inbegrepen. Prijs vanaf 350.000 euro exclusief kosten', '', 350000, 'estepona-magnifiques-appartements-deux-chambres', 'estepona-mooie-tweekamerappartementen', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1477', 'Estepona: Sublimes appartement trois chambres', 'Estepona: mooie driekamerappartementen', '', 'Ce nouveau complexe se trouve entre mer, montagne et golf à courte distance de tous les types de commerces et services, à 45 minutes de l''aéroport de Malaga et à 10 minutes de Marbella. Chaque appartement a été conçu séparément pour optimiser les espaces et la lumière naturelle. Modernité, élégance et fonctionnalité s''unissent dans un style résolument contemporain. Ils sont proposés en deux, trois ou quatre chambres Les espaces communs sont richement dotés avec de beaux jardins, deux piscines, une salle de sport et un club house. Les cuisines sont équipées d''une plaque à induction, un four , un micro-ondes et une hotte. Un parking et une cave sont compris dans le prix. Prix: à partir de 355.000 ? hors frais Fin des travaux : décembre 2025', 'Dit nieuwe complex is gelegen tussen de zee, de bergen en de golfbaan op korte afstand van alle soorten winkels en diensten, op 45 minuten van het vliegveld van Malaga en 10 minuten van Marbella. Elk appartement is afzonderlijk ontworpen om de ruimte en het natuurlijke licht te optimaliseren. Moderniteit, elegantie en functionaliteit worden gecombineerd in een resoluut eigentijdse stijl en zijn beschikbaar in twee, drie of vier slaapkamers. De gemeenschappelijke ruimtes zijn rijkelijk voorzien van prachtige tuinen, twee zwembaden, een fitnessruimte en een clubhuis. De keukens zijn uitgerust met een inductiekookplaat, oven, magnetron en afzuigkap. Parkeren en een kelder zijn bij de prijs inbegrepen. Prijs vanaf 355.000 euro exclusief kosten', '', 355000, 'estepona-sublimes-appartement-trois-chambres', 'estepona-mooie-driekamerappartementen', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1478', 'Estepona: appartements exceptionnels en quatre chambres', 'Estepona: prachtige appartementen met vier slaapkamers', '', 'Ce nouveau complexe se trouve entre mer, montagne et golf à courte distance de tous les types de commerces et services, à 45 minutes de l''aéroport de Malaga et à 10 minutes de Marbella. Chaque appartement a été conçu séparément pour optimiser les espaces et la lumière naturelle. Modernité, élégance et fonctionnalité s''unissent dans un style résolument contemporain. Ils sont proposés en deux, trois ou quatre chambres. Les espaces communs sont richement dotés avec de beaux jardins, deux piscines, une salle de sport et un club house. Les cuisines sont équipées d''une plaque à induction, un four, un micro-ondes et une hotte. Un parking et une cave sont compris dans le prix. Prix: à partir de 533.000 ? hors frais', 'Dit nieuwe complex is gelegen tussen de zee, de bergen en de golfbaan op korte afstand van alle soorten winkels en diensten, op 45 minuten van het vliegveld van Malaga en 10 minuten van Marbella. Elk appartement is afzonderlijk ontworpen om de ruimte en het natuurlijke licht te optimaliseren. Moderniteit, elegantie en functionaliteit worden gecombineerd in een resoluut eigentijdse stijl en zijn beschikbaar in twee, drie of vier slaapkamers. De gemeenschappelijke ruimtes zijn rijkelijk voorzien van prachtige tuinen, twee zwembaden, een fitnessruimte en een clubhuis. De keukens zijn uitgerust met een inductiekookplaat, oven, magnetron en afzuigkap. Parkeren en een kelder zijn bij de prijs inbegrepen. Prijs: vanaf 533.000 euro exclusief kosten', '', 533000, 'estepona-appartements-exceptionnels-en-quatre-chambres', 'estepona-prachtige-appartementen-met-vier-slaapkamers', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1485', 'Gran Alacant: extraordinaires appartements deux chambres avec vue mer', 'Gran Alacant: buitengewone appartementen met twee slaapkamers met uitzicht op zee', '', 'Cette nouvelle résidence compte 170 appartements à Gran Alacant, avec vue sur la Méditerranée et accès direct à la plage de Carabassi, distinguée par le Pavillon bleu. Les appartements de 3 chambres et 2 salles de bain bénéficient d?une distribution soignée et d?une superbe vue sur la mer, la plage, la piscine et les jardins privés du lotissement. Les appartements neufs, aux finitions de qualité supérieure, forment une belle résidence avec piscine, parking souterrain privé, débarras, jardins, circuit santé, stationnement cyclable et aire de jeux pour enfants. La résidence se trouve à 15 minutes à pied de la plage de Carabassi. Leur cadre naturel, leur magnifique emplacement entre les communes d?El Altet et Santa Pola, et leurs plages de dunes font de ces appartements, l?une des meilleures opportunités d?achat sur la Costa Blanca. Prix: A partir de 405.000 ? hors frais', 'Deze nieuwe residentie heeft 170 appartementen in Gran Alacant, met uitzicht op de Middellandse Zee en directe toegang tot het Carabassi-strand, onderscheiden door de Blauwe Vlag. De appartementen met 3 slaapkamers en 2 badkamers profiteren van een zorgvuldige verdeling en een prachtig uitzicht op de zee, het strand, het zwembad en de privétuinen van de woonwijk. De nieuwe appartementen, met hoogwaardige afwerking, vormen een prachtige residentie met zwembad, ondergrondse privéparking, berging, tuinen, gezondheidscircuit, fietsenstalling en kinderspeelplaats. De residentie ligt op 15 minuten lopen van het strand van Carabassi. Hun natuurlijke omgeving, hun prachtige ligging tussen de steden El Altet en Santa Pola en hun duinstranden maken deze appartementen een van de beste winkelmogelijkheden aan de Costa Blanca. Prijs: Vanaf ? 405.000 exclusief kosten', '', 405000, 'gran-alacant-extraordinaires-appartements-deux-chambres-avec-vue-mer', 'gran-alacant-buitengewone-appartementen-met-twee-slaapkamers-met-uitzicht-op-zee', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1486', 'Gran Alacant: fabuleux appartements trois chambres avec vue mer', 'Gran Alacant: fantastische appartementen met drie slaapkamers en uitzicht op zee', '', 'Cette nouvelle résidence compte 170 appartements à Gran Alacant, avec vue sur la Méditerranée et accès direct à la plage de Carabassi, distinguée par le Pavillon bleu. Les appartements de 2 et 3 chambres et 2 salles de bain bénéficient d?une distribution soignée et d?une superbe vue sur la mer, la plage, la piscine et les jardins privés du lotissement. Les appartements neufs, aux finitions de qualité supérieure, forment une belle résidence avec piscine, parking souterrain privé, débarras, jardins, circuit santé, stationnement cyclable et aire de jeux pour enfants. La résidence se trouve à 15 minutes à pied de la plage de Carabassi. Leur cadre naturel, leur magnifique emplacement entre les communes d?El Altet et Santa Pola, et leurs plages de dunes font de ces appartements, l?une des meilleures opportunités d?achat sur la Costa Blanca. Prix: Rez: de 380.000 ? à 430.000 ? hors frais 1er étage: de 350.000 ? à 365.000 ? hors frais Penthouses: 440.000 ? hors frais Livraison: novembre 2024', 'Deze nieuwe residentie heeft 170 appartementen in Gran Alacant, met uitzicht op de Middellandse Zee en directe toegang tot het Carabassi-strand, onderscheiden door de Blauwe Vlag. De appartementen met 2 en 3 slaapkamers en 2 badkamers profiteren van een zorgvuldige verdeling en een prachtig uitzicht op de zee, het strand, het zwembad en de privétuinen van de woonwijk. De nieuwe appartementen, met hoogwaardige afwerking, vormen een prachtige residentie met zwembad, ondergrondse privéparkeerplaats, berging, tuinen, gezondheidscircuit, fietsenstalling en kinderspeelplaats. De residentie ligt op 15 minuten lopen van het strand van Carabassi. Hun natuurlijke omgeving, hun prachtige ligging tussen de steden El Altet en Santa Pola en hun duinstranden maken deze appartementen een van de beste winkelmogelijkheden aan de Costa Blanca. Prijs: Gelijksvloers: van ?380.000 tot ?430.000 exclusief kosten 1ste verdieping: van ?350.000 tot ?365.000 exclusief kosten Penthouse: ?440.000 exclusief kosten Oplevering: november 2024', '', 350000, 'gran-alacant-fabuleux-appartements-trois-chambres-avec-vue-mer', 'gran-alacant-fantastische-appartementen-met-drie-slaapkamers-en-uitzicht-op-zee', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1491', 'Cumbre del Sol: Remarquable villa quatre chambres', 'Cumbre del Sol: Opmerkelijke villa met vier slaapkamers', '', 'Cette villa se distingue par un design complètement ouvert sur l''extérieur et sur la mer. La villa propose des espaces très généreux avec une distribution ouverte en trois zones distingues: une zone salle de TV, une zone salon et une dernière pour la salle à manger connectée à la cuisine dotée d''un majestueux îlot central. Le passage vers les terrasses extérieures peut se faire de tout côté. Une superbe piscine et une terrasse couverte vous feront profiter de l''air libre et de l''air pur de la Costa Blanca pendant presque toute l''année. La chambre principale mérite aussi une mention spéciale avec une salle de bains en suite comprenant une double vasque, une baignoire et une douche. Un dressing vient compléter la distribution. La villa offre au total quatre chambres, toutes avec salle de bains en suite, dressing ou placards intégrés. Les chambres communiquent toutes avec la terrasse offrant de splendides vues sur la mer, sur la piscine à débordement, sur les jardins. Enfin un parking pour deux voitures, les électroménagers de la marque Miele ou similaires, la climatisation Daikin sont aussi inclus dans le prix. Prix: 2.475.000 euros hors frais', 'Deze villa onderscheidt zich door een ontwerp dat volledig openstaat naar buiten en naar de zee.De villa biedt zeer royale ruimtes met een open verdeling in drie onderscheiden ruimtes: een tv-kamer, een lounge en een leest voor de eetkamer. eetkamer verbonden met de keuken met een majestueus centraal eiland. De doorgang naar de buitenterrassen kan van elke zijde worden gedaan. Een prachtig zwembad en een overdekt terras laten u het grootste deel van het jaar genieten van de frisse en schone lucht van de Costa Blanca. De hoofdslaapkamer verdient ook een speciale vermelding met een en-suite badkamer met een dubbele wastafel, een bad en een douche. Een kleedkamer maakt de distributie compleet. De villa heeft in totaal vier slaapkamers, allemaal met en-suite badkamers, inloopkasten of inbouwkasten. De kamers communiceren allemaal met het terras en bieden een prachtig uitzicht op de zee, het overloopzwembad en de tuinen. Eindelijk parkeergelegenheid voor twee auto''s, Miele-apparaten of iets dergelijks, Daikin-airconditioning is ook bij de prijs inbegrepen. Prijs : 2.475.000 euro exclusief kosten', '', 2475000, 'cumbre-del-sol-remarquable-villa-quatre-chambres', 'cumbre-del-sol-opmerkelijke-villa-met-vier-slaapkamers', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1492', 'cumbre del Sol: exceptionnelle villa de luxe 4 chambres avec vue mer', 'Cumbre del Sol: uitzonderlijke luxe villa met 4 slaapkamers en zeezicht', '', 'Cette villa exclusive est construite sur une parcelle de 2.122 m². Elle se caractérise par des volumes peu communs et des espaces baignés de lumière naturelle. Elle est proposée en quatre chambres et 5 salles de bains mais avec la possibilité d''ajouter une chambre supplémentaire. Toutes les chambres sont grandes et lumineuses et disposent chacune de leur propre salle de bains. La chambre parentale est en plus dotée d''un grand dressing, d''une belle terrasse et de vue sur la mer. La partie jour est un lieu idéal pour recevoir ses amis ou une grande famille. La partir salle à manger se love sous une double hauteur sous plafond, ce qui inonde du coup la pièce de lumière naturelle. Depuis la cuisine ouverte où se trouve une deuxième salle à manger, les grandes baies vitrées donnent sur une immense terrasse, une zone chill out et une piscine à débordement avec jacuzzi. Le niveau inférieur est considéré comme un extra pouvant accueillir par exemple un appartement complet. Enfin un grand garage peut accueillir trois voitures et un ascenseur est prévu pour offrir un maximum de confort et de fonctionnalité. Prix: 5.176.000 euros hors frais', 'Deze exclusieve villa is gebouwd op een perceel van 2.122 m². Het wordt gekenmerkt door ongebruikelijke volumes en ruimtes die baden in natuurlijk licht. Het is beschikbaar in vier slaapkamers en 5 badkamers, maar met de mogelijkheid om een ??extra slaapkamer toe te voegen. Alle slaapkamers zijn groot en licht en hebben elk een eigen badkamer. De hoofdslaapkamer heeft ook een grote kleedkamer, een mooi terras en uitzicht op zee. Het daggedeelte is een ideale plek om vrienden of een groot gezin te ontvangen. De eetkamer is genesteld onder een dubbele hoogte onder het plafond, die de kamer plotseling overspoelt met natuurlijk licht. Vanuit de open keuken waar een tweede eetkamer is, komen de grote erkers uit op een enorm terras, een relaxruimte en een overloopzwembad met jacuzzi. Het lagere niveau wordt beschouwd als een extraatje dat bijvoorbeeld plaats biedt aan een compleet appartement. Ten slotte biedt een grote garage plaats aan drie auto''s en is er een lift voor maximaal comfort en functionaliteit. Prijs vanaf 5.176.000 euro exclusief kosten', '', 5176000, 'cumbre-del-sol-exceptionnelle-villa-de-luxe-4-chambres-avec-vue-mer', 'cumbre-del-sol-uitzonderlijke-luxe-villa-met-4-slaapkamers-en-zeezicht', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1534', 'San Juan de los Terreros: beaux appartements 1 chambre à proximité de la mer', '', '', 'Toute nouvelle résidence de style Andalou, parfaitement intégrée dans le paysage, située à quelques pas de la mer, à proximité d''un petit village typique et à seulement 10 min de la ville d''Aguilas. La résidence dispose de 2 piscines communes, de 2 jacuzzis et de magnifiques jardins communs. A distance de marche, vous trouverez également un petit centre commercial avec supérette, ainsi que plusieurs cafés et restaurants. Les appartements du rez-de-chaussée disposent d''une terrasse et d''un jardin, ceux du 1er étage bénéficient d''une terrasse et les appartements du 2ème étage disposent d''un solarium. Prix: A partir de 157.000 ? hors frais Inclus dans le prix: place de parking en sous-sol.', '', '', 157000, 'san-juan-de-los-terreros-beaux-appartements-1-chambre-a-proximite-de-la-mer', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1535', 'San Juan de los Terreros: beaux appartements 2 chambres à proximité de la mer', '', '', 'Nouvelle résidence de style Andalou, parfaitement intégrée dans le paysage, située à quelques pas de la mer, à proximité d''un petit village typique et à seulement 10 min de la ville d''Aguilas. La résidence dispose de 2 piscines communes, de 2 jacuzzis et de magnifiques jardins communs. A distance de marche, vous trouverez également un petit centre commercial avec supérette, ainsi que plusieurs cafés et restaurants. Les appartements du rez-de-chaussée disposent d''une terrasse et d''un jardin, ceux du 1er étage bénéficient d''une terrasse et les appartements du 2ème étage disposent d''un solarium. Les appartements ont une buanderie, une cuisine ouverte sur le salon et la salle à manger, 2 chambres, 1 ou 2 salles de bains et un parking en sous-sol. Certains appartements ont également une cave. Prix: à partir de 182.000 ? hors frais KEY READY !', '', '', 182000, 'san-juan-de-los-terreros-beaux-appartements-2-chambres-a-proximite-de-la-mer', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1536', 'San Juan de los Terreros: beaux appartements 3 chambres à proximité de la mer', '', '', 'Toute nouvelle résidence de style Andalou, parfaitement intégrée dans le paysage, située à quelques pas de la mer, à proximité d''un petit village typique et à seulement 10 min de la ville d''Aguilas. La résidence dispose de 2 piscines communes, de 2 jacuzzis et de magnifiques jardins communs. A distance de marche, vous trouverez également un petit centre commercial avec supérette, ainsi que plusieurs cafés et restaurants. Les appartements du rez-de-chaussée disposent d''une terrasse et d''un jardin, ceux du 1er étage bénéficient d''une terrasse et les appartements du 2ème étage disposent d''un solarium. Les appartements 3 chambres ont une buanderie, une cuisine ouverte sur le salon et la salle à manger, 2 chambres, 2 salles de bains et un parking en sous-sol. Certains appartements ont également une cave. Prix: à partir de 228.000 ? hors frais', '', '', 228000, 'san-juan-de-los-terreros-beaux-appartements-3-chambres-a-proximite-de-la-mer', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1552', 'Dans un golf prestigieux, superbes villas 3 chambres', '', '', 'Les villas, de plain-pied, disposent de 3 chambres, de 2 salles de bains, d''une cuisine ouverte et d''un living donnant sur le jardin avec la piscine privée et d''un emplacement de parking. Elles sont construites sur des parcelles de 500 m². Ces villas sont situées dans un superbe golf, à 12 km des belles plages de Guardamar. Le resort propose de nombreuses facilités, telles qu''un hôtel 5* avec welness, un clubhouse, des terrains de tennis et de paddle, une écolde de golf, des petits commerces,... Prix: à partir de 549.000 ? hors frais. Inclus dans le prix: piscine privée de 6x4m, chauffage au sol dans les salles de bains.', '', '', 549000, 'dans-un-golf-prestigieux-superbes-villas-3-chambres', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1874', 'El Verger: superbes appartements 2 chambres à 500 m de la mer', '', '', 'A El Verger, non loin de Denia, cette nouvelle résidence est située à 500 m de la mer et à proximité de nombreuses facilités, telles que supermarchés, bars, restaurants... La résidence compte plusieurs zones communes pour vous balader ou pratiquer du sport, ainsi qu''une superbe piscine, un club social, un terrain de pétanque, un espace détente, un point de recharge pour vélos électriques... Les résidents auront également accès à un club social privé à la plage avec parking, piscine, douches, casiers,... Le projet est conçu autour des stratégies durables : des systèmes de collecte, de canalisation et de réutilisation des eaux de pluie; des jardins rafraîchissants avec des espèces indigènes nécessitant un entretien minimal; des panneaux photovoltaïques pour la production d''énergie par autoconsommation; plusieurs bornes de recharge pour véhicules électriques. Les appartements 2 chambres et 2 salles de bains sont spacieux et disposent de belles grandes terrasses vous permettant de profiter pleinement du climat méditerranéen. Prix: à partir de 316.000 ? hors frais Inclus dans le prix: - climatisation - électroménagers: taque à induction, four, micro-ondes et hotte', '', '', 316000, 'el-verger-superbes-appartements-2-chambres-a-500-m-de-la-mer', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1554', 'Villas 4 chambres dans un prestigieux golf', '', '', 'Superbes villas 4 chambres jouissant de magnifiques vues sur golf, à 10 minutes des belles plages de Guardamar. Situation idéale, au calme, facilement accessible via les aéroports internationaux d''Alicante et de Murcie. Vous serez séduits par la disposition idéale, la luminosité agréable et les finitions de cette propriété de standing avec piscine privée. Les villas sont construites sur des parcelles allant de 317 m² à 550 m² et disposent de 3 niveaux: - sous-sol - Rez-de-chaussée: cuisine ouverte sur un living spacieux, une chambre, une salle de bains et un WC séparé. Depuis le living et la chambre, accès direct au jardin avec la piscine privée. - 1er étage: chambre parentale avec dressing, salle de bains privée et terrasse de 19m², 2 chambres supplémentaires et une salle de bains. Le resort de golf propose de nombreuses facilités, telles qu''un hôtel 5* avec wellness, un clubhouse, des terrains de tennis et de paddle, une école de golf, des petits commerces,... Prix: à partir de 729.000 ? hors frais Inclus dans le prix: électroménagers, piscine de 8x4m, jardin aménagé, chauffage au sol dans les salles de bains, système domotique', '', '', 729000, 'villas-4-chambres-dans-un-prestigieux-golf', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1566', 'Avilese (Murcia): belles maisons trois chambres à 15 minutes des plages', 'Avilese (Murcia): prachtige huizen met drie slaapkamers op 15 minuten van de stranden', '', 'Prix incroyables pour ces maisons avec piscine privée offrant trois chambres et deux salles de bains. A proximité de Murcie et des plages de la Mar Menor, ces villas disposent de toutes les commodités. Rez-de-chaussée: cuisine ouverte donnant sur le séjour, 1 chambre et 1 salle de bains. Petite buanderie à l''arrière. 1er étage: 2 chambres avec accès direct à une terrasse de 18 m² et 1 salle de bains. 2ème étage: solarium Sont inclus dans le prix: la piscine et les électroménagers. Prix: à partir de 269.000 ? hors frais Fin des travaux: mai 2026', 'Ongelooflijke prijzen voor deze huizen met privézwembad met drie slaapkamers en twee badkamers. Begane grond: open keuken die uitkomt op de woonkamer, 1 slaapkamer en 1 badkamer. Kleine wasruimte aan de achterkant. 1ste verdieping: 2 slaapkamers met directe toegang tot een terras van 18 m² en 1 badkamer. 2de verdieping: solarium In de prijs inbegrepen: zwembad en elektrische apparaten Prijs: vanaf ?269.000 exclusief kosten Oplevering: mei 2026', '', 269000, 'avilese-murcia-belles-maisons-trois-chambres-a-15-minutes-des-plages', 'avilese-murcia-prachtige-huizen-met-drie-slaapkamers-op-15-minuten-van-de-stranden', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1628', 'DERNIERE UNITE !Algorfa: Charmantes villas contemporaines en 3 chambres', '', '', 'Ce nouveau complexe de villas se trouve dans l''un des plus beaux golfs de la Costa Blanca Sud. A l''entrée du domaine, se trouvent restaurants, cafés, boutiques et magasin d''alimentation. Dans le village tout proche, vous profiterez de toutes les autres commodités. Les superbes plages de Guardamar sont à 10 minutes en voiture. L''aéroport se situe à 30 minutes de la résidence. Deux modèles de villas sont proposés, l''un des modèles propose un débarras de 2 m² en plus. Les villas de style contemporain, construite en L, ont aussi un caractère méditerranéen grâce à l''utilisation de matériaux locaux. Une grande pièce de jour regroupe cuisine, salle à manger et salon. De grandes baies vitrées baignent ce bel espace de lumière naturelle. Dans l''aile du bâtiment se trouvent les 3 chambres et les salles de bains dont une en suite. Chaque villa dispose de sa piscine privée (8m x 3m), d''un jardin privatif et d''un solarium. Une place de parking est prévue sur la parcelle. Le choix des matériaux et les finitions sont de qualité supérieure. La piscine, les électroménagers, la domotique, le système d''alarme, l''aménagement complet du jardin et le chauffage sol dans les salles de bains sont inclus dans le prix. Prix: de 595.000 ? hors frais (avec sous-sol de 114 m² inclus)', '', '', 595000, 'derniere-unite-algorfa-charmantes-villas-contemporaines-en-3-chambres', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1585', 'Aspe: Luxueuses villas individuelles en première ligne de golf', '', '', 'Ces villas bénéficient d''un environnement exceptionnel et d''une exposition plein sud. Une vue incroyable et imprenable sur le golf et sur les montagnes ravira les amoureux de la nature et de la quiétude. La localisation est excellente: à 5 minutes se trouve la ville d''Aspe avec ses commodités et à 15 minutes la ville d''Alicante vous offre toutes les infrastructures d''une grande ville ( gastronomie, culture, équipements sportifs, sports nautiques et plages paradisiaques). Un sous-sol avec garage pour 4 voitures, une cave à vin et une salle de sport est possible en option. Au rez-de-chaussée se trouvent la cuisine ouverte et complètement équipée, la salle à manger, le salon, un wc invité séparé, la suite parentale (avec dressing et salle de bain), deux chambres invités, une salle de bain et un patio. La piscine privée, deux grandes terrasses dont une couverte et un magnifique jardin complète la composition. Au premier étage, vous trouverez la quatrième chambre avec dressing et salle de bains en suite ainsi qu''un immense terrasse et un très grand solarium! Prix: 1.795.000 ? hors frais', '', '', 1795000, 'aspe-luxueuses-villas-individuelles-en-premiere-ligne-de-golf', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1597', 'Santa Rosalia: luxueuses villas trois chambres dans un cadre d''exception', '', '', 'Ce nouveau concept révolutionne le concept d''urbanisation ! Le resort est construit autour d''un lagon artificiel de 16.000 m² et de vastes parcs sur un domaine de plus de 120.000 m². Situé non loin de la mer, il conjugue tous les plaisirs pour les futurs propriétaires: le calme, les activités sur site et la vie balnéaire toute proche avec ses restaurants, cafés et commerces. Dans les magnifiques jardins, vous pourrez contempler la nature luxuriante, jouer au golf, à la pétanque ou simplement vous reposer pendant que les enfants s''amuseront à la plaine de jeux. Les villas sont proposées en trois chambres, trois salles de bains, elles sont dotées d''un solarium, d''un sous-sol avec lumière naturelle et d''une piscine privée compris dans le prix. Deux des chambres sont distribuées en suite avec salle de bains et dressing et une des deux à une accès direct à une belle terrasse de 18m². Prix à partir de 505.000 ? hors frais', '', '', 505000, 'santa-rosalia-luxueuses-villas-trois-chambres-dans-un-cadre-d-exception', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1599', 'Campoamor: sublimes villas 3 chambres au c?ur d''un magnifique golf', '', '', 'Ces extraordinaires villas se lovent dans un superbe domaine de golf à Campoamor. Elles sont de style contemporain tout en ne reniant pas un côté méditerranéen. De grandes baies vitrées laissent pénétrer la lumière naturelle et offrent une vue panoramique sur la pinède. Les villas sont construites sur des parcelles de +/-600m², disposent d''une belle piscine de 38 m², de l''air conditionné, d''un sol chauffant dans les salles de bains, du smart home system et enfin, d''un garage ou d''un sous-sol. Prix: 690.000? hors frais', '', '', 690000, 'campoamor-sublimes-villas-3-chambres-au-c-ur-d-un-magnifique-golf', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false)
